                className="bg-black text-white px-6 py-2 rounded-sm hover:bg-gray-900 transition-colors"
              >
                Start Building
              </button>
            </nav>
          </div>
        </div>
      </header>

      {renderPage()}
    </div>
  );
};

export default OCXLanding;
